import { GoogleGenAI, Type } from "@google/genai";
import { Language, LexicalEntry } from "../types";

const generateId = () => {
  if (typeof crypto !== 'undefined' && crypto.randomUUID) {
    return crypto.randomUUID();
  }
  return 'lex-' + Date.now() + '-' + Math.random().toString(36).substring(2, 11);
};

export async function translateWord(
  query: string, 
  sourceLanguage: Language, 
  targetLanguage: Language
): Promise<LexicalEntry> {
  const apiKey = (process.env.API_KEY || "").trim();
  const ai = new GoogleGenAI({ apiKey });

  const prompt = `Act as a master philologist. Analyze and translate "${query}" from ${sourceLanguage} to ${targetLanguage}.

Provide a deep dictionary-style entry in JSON including:
1. term: The exact form provided.
2. lemma: Base form.
3. inflection: Grammatical analysis.
4. Philological analysis: Etymology, historical notes.
5. Language Level: CEFR level (A1-C2).
6. Cultural context: Register (formal/informal/neutral) and usage notes.
7. Lexical Relations: 3-5 synonyms in ${sourceLanguage}.
8. Semantic variations: alternative translations in ${targetLanguage}.
9. Literary manifestations: Quotes or proverbs.
10. Idioms: Common expressions.

Rules:
- German: include gender/plural.
- Uzbek: modern Latin.
- Return ONLY JSON.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      // Removing thinkingBudget to stabilize response on mobile and simplifying the request
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          term: { type: Type.STRING },
          lemma: { type: Type.STRING },
          inflection: { type: Type.STRING },
          mainTranslation: { type: Type.STRING },
          sourceLevel: { type: Type.STRING },
          philology: {
            type: Type.OBJECT,
            properties: {
              etymology: { type: Type.STRING },
              historicalNotes: { type: Type.STRING },
              partOfSpeech: { type: Type.STRING },
              gender: { type: Type.STRING },
              plural: { type: Type.STRING }
            },
            required: ["etymology", "partOfSpeech"]
          },
          culture: {
            type: Type.OBJECT,
            properties: {
              usage: { type: Type.STRING },
              register: { type: Type.STRING },
              notes: { type: Type.STRING }
            },
            required: ["usage", "register", "notes"]
          },
          synonyms: { type: Type.ARRAY, items: { type: Type.STRING } },
          variations: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                text: { type: Type.STRING },
                confidence: { type: Type.NUMBER },
                source: { type: Type.STRING }
              }
            }
          },
          literature: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                text: { type: Type.STRING },
                translation: { type: Type.STRING },
                source: { type: Type.STRING },
                author: { type: Type.STRING }
              }
            }
          },
          idioms: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                text: { type: Type.STRING },
                translation: { type: Type.STRING },
                explanation: { type: Type.STRING },
                type: { type: Type.STRING }
              }
            }
          }
        },
        required: ["term", "mainTranslation", "philology", "culture"]
      }
    }
  });

  const text = response.text;
  if (!text) throw new Error("The Lexicon returned an empty scroll.");

  let rawData;
  try {
    rawData = JSON.parse(text);
  } catch (e) {
    console.error("Linguistic Parsing Failed:", text);
    throw new Error("The archive returned malformed inscriptions.");
  }

  // Defensive mapping to handle missing properties on various mobile browsers
  return {
    id: generateId(),
    term: rawData.term || query,
    lemma: rawData.lemma || rawData.term || query,
    inflection: rawData.inflection || "",
    normalizedTerm: query.toLowerCase().trim(),
    mainTranslation: rawData.mainTranslation || "Translation unknown",
    sourceLang: sourceLanguage,
    targetLang: targetLanguage,
    sourceLevel: rawData.sourceLevel || "Unranked",
    philology: {
      etymology: rawData.philology?.etymology || "Etymology undocumented.",
      historicalNotes: rawData.philology?.historicalNotes || "",
      partOfSpeech: rawData.philology?.partOfSpeech || "Unknown",
      gender: rawData.philology?.gender || "",
      plural: rawData.philology?.plural || ""
    },
    culture: {
      usage: rawData.culture?.usage || "General use",
      register: (rawData.culture?.register as any) || "neutral",
      notes: rawData.culture?.notes || "No cultural notes available."
    },
    synonyms: rawData.synonyms || [],
    variations: (rawData.variations || []).map((v: any) => ({
      text: v.text || "",
      confidence: v.confidence || 0.5,
      source: 'ai'
    })),
    literature: (rawData.literature || []).map((lit: any) => ({
      text: lit.text || "",
      translation: lit.translation || "",
      source: lit.source || "General Lore",
      author: lit.author || "Anonymous"
    })),
    idioms: (rawData.idioms || []).map((idm: any) => ({
      text: idm.text || "",
      translation: idm.translation || "",
      explanation: idm.explanation || "",
      type: idm.type || 'general'
    })),
    timestamp: Date.now()
  };
}

export async function generateQuiz(entries: LexicalEntry[]) {
  const apiKey = (process.env.API_KEY || "").trim();
  const ai = new GoogleGenAI({ apiKey });

  const context = entries.map(e => `${e.term} -> ${e.mainTranslation} (from ${e.sourceLang} to ${e.targetLang})`).join(", ");

  const prompt = `You are a linguistic quiz generator. 
Task: Create exactly TWO multiple-choice questions for each word in this list: ${context}.

STRICT FORMAT RULES:
1. The 'question' field MUST ONLY be the word itself. No extra text, no sentences.
2. One question should ask for the translation from source to target. 
3. One question should ask for the translation from target to source.
4. 'options' must be a list of exactly 3 or 4 single words (the correct translation and plausible distractors).
5. 'explanation' should be a brief philological note about the word's meaning or usage.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            question: { type: Type.STRING },
            correctAnswer: { type: Type.STRING },
            options: { type: Type.ARRAY, items: { type: Type.STRING } },
            explanation: { type: Type.STRING }
          },
          required: ["question", "correctAnswer", "options", "explanation"]
        }
      }
    }
  });

  try {
    return JSON.parse(response.text || '[]');
  } catch (e) {
    return [];
  }
}

