export async function translateWord(
  query: string, 
  sourceLanguage: Language, 
  targetLanguage: Language
): Promise<LexicalEntry> {
  const apiKey = (process.env.API_KEY || "").trim();
  const ai = new GoogleGenAI({ apiKey });

  // High-velocity prompt for instant dictionary lookups
  const prompt = `Dictionary Task: Translate "${query}" (${sourceLanguage} -> ${targetLanguage}). 
Provide: Etymology (1 sentence), Part of speech, Translation, Gender/Plural if German, 2 synonyms, 1 variant, 1 quote, 1 idiom. 
STRICT: Be concise. Use Latin script for Uzbek. Return ONLY JSON.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      temperature: 0.1, 
      topK: 1,         // Greedy selection for speed
      topP: 0.1,       // Low sampling variety
      maxOutputTokens: 350, // Strict cap to prevent stalling
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          term: { type: Type.STRING },
          translation: { type: Type.STRING },
          pos: { type: Type.STRING },
          etymology: { type: Type.STRING },
          gender: { type: Type.STRING },
          plural: { type: Type.STRING },
          synonyms: { type: Type.ARRAY, items: { type: Type.STRING } },
          variant: { type: Type.STRING },
          quote: { type: Type.STRING },
          quote_translation: { type: Type.STRING },
          idiom: { type: Type.STRING },
          idiom_translation: { type: Type.STRING }
        },
        required: ["term", "translation", "pos", "etymology"]
      }
    }
  });

  const text = response.text;
  if (!text) throw new Error("The Archive is silent.");

  let raw;
  try {
    raw = JSON.parse(text);
  } catch (e) {
    throw new Error("Linguistic parsing error.");
  }

  // Mapping flat fast response to the rich LexicalEntry structure
  return {
    id: generateId(),
    term: raw.term || query,
    lemma: raw.term || query,
    inflection: "",
    normalizedTerm: query.toLowerCase().trim(),
    mainTranslation: raw.translation || "...",
    sourceLang: sourceLanguage,
    targetLang: targetLanguage,
    sourceLevel: "A1",
    philology: {
      etymology: raw.etymology || "Etymology unknown.",
      partOfSpeech: raw.pos || "Unknown",
      gender: raw.gender || "",
      plural: raw.plural || ""
    },
    culture: {
      usage: "General",
      register: "neutral",
      notes: ""
    },
    synonyms: raw.synonyms || [],
    variations: raw.variant ? [{ text: raw.variant, confidence: 0.95, source: 'ai' }] : [],
    literature: raw.quote ? [{
      text: raw.quote,
      translation: raw.quote_translation || "",
      source: "Lore"
    }] : [],
    idioms: raw.idiom ? [{
      text: raw.idiom,
      translation: raw.idiom_translation || "",
      explanation: "",
      type: 'general'
    }] : [],
    timestamp: Date.now()
  };
}

