import { GoogleGenAI, Type } from "@google/genai";
import { Language, LexicalEntry } from "../types";

const generateId = () => {
  if (typeof crypto !== 'undefined' && crypto.randomUUID) {
    return crypto.randomUUID();
  }
  return 'lex-' + Date.now() + '-' + Math.random().toString(36).substring(2, 11);
};

export async function translateWord(
  query: string, 
  sourceLanguage: Language, 
  targetLanguage: Language
): Promise<LexicalEntry> {
  const apiKey = (process.env.API_KEY || "").trim();
  const ai = new GoogleGenAI({ apiKey });

  // High-speed keyword-based prompt
  const prompt = `Task: Philological translation of "${query}" (${sourceLanguage} -> ${targetLanguage}).
Format: Concise JSON. 
Details: Etymology (1 sentence), Grammatical class, Gender/Plural (for German), 2-3 Synonyms, 1-2 Variations, 1 Quote (optional), 1 Idiom (optional). 
Script: Use Latin for Uzbek.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      temperature: 0,   // Zero randomness for maximum speed
      topK: 1,          // Greedy decoding
      topP: 0.1,        // Focus on high-probability tokens
      maxOutputTokens: 350, // Prevent stalling on long generations
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          term: { type: Type.STRING },
          translation: { type: Type.STRING },
          pos: { type: Type.STRING },
          etymology: { type: Type.STRING },
          gender: { type: Type.STRING },
          plural: { type: Type.STRING },
          level: { type: Type.STRING },
          synonyms: { type: Type.ARRAY, items: { type: Type.STRING } },
          variations: { type: Type.ARRAY, items: { type: Type.STRING } },
          quote: { type: Type.STRING },
          quote_tr: { type: Type.STRING },
          idiom: { type: Type.STRING },
          idiom_tr: { type: Type.STRING }
        },
        required: ["term", "translation", "pos", "etymology"]
      }
    }
  });

  const text = response.text;
  if (!text) throw new Error("Empty Archive Response");

  let raw;
  try {
    raw = JSON.parse(text);
  } catch (e) {
    throw new Error("Linguistic Parsing Failure");
  }

  // Fast mapping to LexicalEntry
  return {
    id: generateId(),
    term: raw.term || query,
    lemma: raw.term || query,
    inflection: "",
    normalizedTerm: query.toLowerCase().trim(),
    mainTranslation: raw.translation || "Unknown",
    sourceLang: sourceLanguage,
    targetLang: targetLanguage,
    sourceLevel: raw.level || "A1",
    philology: {
      etymology: raw.etymology || "Etymology research in progress.",
      partOfSpeech: raw.pos || "Unknown",
      gender: raw.gender || "",
      plural: raw.plural || ""
    },
    culture: {
      usage: "General",
      register: "neutral",
      notes: ""
    },
    synonyms: raw.synonyms || [],
    variations: (raw.variations || []).map((v: string) => ({
      text: v,
      confidence: 0.95,
      source: 'ai'
    })),
    literature: raw.quote ? [{
      text: raw.quote,
      translation: raw.quote_tr || "",
      source: "Philological Archive"
    }] : [],
    idioms: raw.idiom ? [{
      text: raw.idiom,
      translation: raw.idiom_tr || "",
      explanation: "",
      type: 'general'
    }] : [],
    timestamp: Date.now()
  };
}

