import React, { useState, useMemo, useEffect, useRef, useCallback } from 'react';
import { Language, LexicalEntry, UserProfile } from '../types';
import { translateWord } from '../services/gemini';
import { speak, resumeAudioContext } from '../services/tts';
import { SEED_ARCHIVE } from '../constants';
import { fetchGlobalEntry, saveGlobalEntry, fetchSuggestions } from '../services/supabase';
import ResultCard from './ResultCard';
import HistoryGrid from './HistoryGrid';
import { triggerHaptic } from '../services/telegram';

interface Props {
  onEntrySaved: (entry: LexicalEntry) => void;
  autoAudio: boolean;
  setAutoAudio: (val: boolean) => void;
  profile: UserProfile;
  history: LexicalEntry[];
  onStartArena: () => void;
  selectedEntry?: LexicalEntry | null;
  onEntryClick: (entry: LexicalEntry) => void;
}

interface SuggestionItem {
  term: string;
  source: 'local' | 'global' | 'seed';
}

const LANGUAGES: Record<Language, string> = {
  German: 'GER',
  Uzbek: 'UZB',
  English: 'ENG',
  Russian: 'RUS'
};

const normalize = (text: string, lang: Language): string => {
  let res = text.trim().toLowerCase();
  if (lang === 'German') {
    res = res.replace(/ä/g, 'ae').replace(/ö/g, 'oe').replace(/ü/g, 'ue').replace(/ß/g, 'ss');
  } else if (lang === 'Russian') {
    res = res.replace(/ё/g, 'е');
  } else if (lang === 'Uzbek') {
    res = res.replace(/[‘’`]/g, "'");
  }
  return res;
};

let activeMicStream: MediaStream | null = null;

const Dictionary: React.FC<Props> = ({ 
  onEntrySaved, 
  autoAudio, 
  setAutoAudio, 
  profile, 
  history, 
  onStartArena, 
  selectedEntry,
  onEntryClick
}) => {
  const [query, setQuery] = useState('');
  const [sourceLang, setSourceLang] = useState<Language>('German');
  const [targetLang, setTargetLang] = useState<Language>('Uzbek');
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<LexicalEntry | null>(null);
  const [suggestions, setSuggestions] = useState<SuggestionItem[]>([]);
  const [showSuggestions, setShowSuggestions] = useState(false);
  const [selectedIndex, setSelectedIndex] = useState(-1);
  const [isListening, setIsListening] = useState(false);
  const [micDenied, setMicDenied] = useState(false);
  const [searchError, setSearchError] = useState<string | null>(null);

  const suggestionRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (selectedEntry) {
      setQuery(selectedEntry.term);
      setResult(selectedEntry);
      setSourceLang(selectedEntry.sourceLang);
      setTargetLang(selectedEntry.targetLang);
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }
  }, [selectedEntry]);

  useEffect(() => {
    const delayDebounce = setTimeout(async () => {
      const trimmedQuery = query.trim().toLowerCase();
      if (trimmedQuery.length >= 2) {
        const localMatches = history
          .filter(e => e.sourceLang === sourceLang && e.term.toLowerCase().includes(trimmedQuery))
          .map(e => ({ term: e.term, source: 'local' as const }));

        const seedMatches = Object.values(SEED_ARCHIVE)
          .filter(e => e?.term && e.term.toLowerCase().includes(trimmedQuery))
          .map(e => ({ term: e!.term!, source: 'seed' as const }));

        let globalMatches: SuggestionItem[] = [];
        try {
          const globalTerms = await fetchSuggestions(query, sourceLang);
          globalMatches = (globalTerms || []).map(term => ({ term, source: 'global' as const }));
        } catch (e) {
          console.warn("Global suggestions fetch failed");
        }

        const combined = [...localMatches, ...seedMatches, ...globalMatches];
        const unique = combined.filter((v, i, a) => 
          a.findIndex(t => t.term.toLowerCase() === v.term.toLowerCase()) === i
        ).slice(0, 8);

        setSuggestions(unique);
        setShowSuggestions(unique.length > 0);
        setSelectedIndex(-1);
      } else {
        setSuggestions([]);
        setShowSuggestions(false);
      }
    }, 200);
    return () => clearTimeout(delayDebounce);
  }, [query, sourceLang, history]);

  useEffect(() => {
    const handleClickOutside = (e: MouseEvent) => {
      if (suggestionRef.current && !suggestionRef.current.contains(e.target as Node)) {
        setShowSuggestions(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const handleSourceLangChange = useCallback(async (lang: Language) => {
    await resumeAudioContext();
    if (lang === targetLang) setTargetLang(sourceLang);
    setSourceLang(lang);
    triggerHaptic('light');
  }, [sourceLang, targetLang]);

  const handleTargetLangChange = useCallback(async (lang: Language) => {
    await resumeAudioContext();
    if (lang === sourceLang) setSourceLang(targetLang);
    setTargetLang(lang);
    triggerHaptic('light');
  }, [sourceLang, targetLang]);

  const localCache = useMemo(() => {
    const cache = new Map<string, LexicalEntry>();
    Object.entries(SEED_ARCHIVE).forEach(([key, entry]) => {
      const parts = key.split('-');
      const sL = parts[1] as Language;
      const tL = parts[2] as Language;
      if (entry.term) {
        const norm = normalize(entry.term, sL);
        cache.set(`${norm}-${sL}-${tL}`, { ...entry, id: `seed-${key}`, normalizedTerm: norm, sourceLang: sL, targetLang: tL } as any);
      }
    });
    history.forEach(entry => {
      const norm = normalize(entry.term, entry.sourceLang);
      cache.set(`${norm}-${entry.sourceLang}-${entry.targetLang}`, entry);
    });
    return cache;
  }, [history]);

  const handleSearch = async (overrideQuery?: string) => {
    const cleanQuery = (overrideQuery || query).trim();
    if (!cleanQuery) return;

    setSearchError(null);
    if (inputRef.current) inputRef.current.blur();

    try { await resumeAudioContext(); } catch (e) {}

    setShowSuggestions(false);
    setQuery(cleanQuery);

    const normQuery = normalize(cleanQuery, sourceLang);
    const cacheKey = `${normQuery}-${sourceLang}-${targetLang}`;

    const localHit = localCache.get(cacheKey);
    if (localHit) {
      setResult(localHit);
      if (autoAudio) speak(localHit.mainTranslation, targetLang).catch(() => {});
      return;
    }

    setLoading(true);
    // Smooth transition: don't clear old result immediately

    try {
      const globalHit = await fetchGlobalEntry(normQuery, sourceLang, targetLang);
      if (globalHit) {
        setResult(globalHit);
        onEntrySaved(globalHit);
        setLoading(false);
        if (autoAudio) speak(globalHit.mainTranslation, targetLang).catch(() => {});
        return;
      }

      const finalEntry = await translateWord(cleanQuery, sourceLang, targetLang);
      finalEntry.normalizedTerm = normQuery;

      setResult(finalEntry);
      onEntrySaved(finalEntry);
      saveGlobalEntry(finalEntry);

      if (autoAudio) speak(finalEntry.mainTranslation, targetLang).catch(() => {});
    } catch (err) {
      console.error("Philologist Engine Failure:", err);
      setSearchError("The archive search timed out. Please try again.");
      triggerHaptic('error');
    } finally {
      setLoading(false);
    }
  };

  const startVoiceSearch = async () => {
    if (isListening) return;
    setMicDenied(false);

    if (!activeMicStream) {
      try {
        activeMicStream = await navigator.mediaDevices.getUserMedia({ audio: true });
      } catch (err) {
        setMicDenied(true);
        triggerHaptic('error');
        return;
      }
    }

    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (!SpeechRecognition) return;

    const recognition = new SpeechRecognition();
    recognition.lang = sourceLang === 'German' ? 'de-DE' : sourceLang === 'Russian' ? 'ru-RU' : sourceLang === 'Uzbek' ? 'uz-UZ' : 'en-US';
    recognition.interimResults = false;

    recognition.onstart = () => {
      setIsListening(true);
      triggerHaptic('medium');
    };

    recognition.onresult = (event: any) => {
      const speechToText = event.results[0][0].transcript;
      setQuery(speechToText);
      handleSearch(speechToText);
    };

    recognition.onerror = () => {
      setIsListening(false);
      triggerHaptic('error');
    };

    recognition.onend = () => setIsListening(false);
    try { recognition.start(); } catch (e) { setIsListening(false); }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') handleSearch();
    if (!showSuggestions) return;
    if (e.key === 'ArrowDown') {
      e.preventDefault();
      setSelectedIndex(prev => (prev + 1) % suggestions.length);
    } else if (e.key === 'ArrowUp') {
      e.preventDefault();
      setSelectedIndex(prev => (prev - 1 + suggestions.length) % suggestions.length);
    } else if (e.key === 'Enter' && selectedIndex >= 0) {
      e.preventDefault();
      const selected = suggestions[selectedIndex];
      setQuery(selected.term);
      handleSearch(selected.term);
    }
  };

  const swapLanguages = useCallback(async () => {
    try { await resumeAudioContext(); } catch(e){}
    setSourceLang(prevS => {
      const currentT = targetLang;
      setTargetLang(prevS);
      return currentT;
    });
    triggerHaptic('medium');
  }, [targetLang]);

  return (
    <div className="space-y-8 md:space-y-16 max-w-7xl mx-auto contain-layout">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-8 pt-4">
        <div className="flex items-center gap-6">
          <div className="space-y-1 border-l-2 border-[#7c1a1a] pl-4 block">
            <span className="text-[8px] uppercase tracking-[0.4em] text-stone-400 font-black">Philological Mastery</span>
            <div className="flex items-baseline gap-2">
              <span className="text-xl md:text-2xl font-black serif text-stone-900 leading-none">{profile.xp}</span>
              <span className="text-[7px] uppercase tracking-[0.2em] text-stone-300 font-bold">Total XP</span>
            </div>
          </div>
        </div>

        <div className="flex flex-col lg:flex-row items-center gap-6 lg:gap-12 w-full md:w-auto">
          <div className="flex flex-col sm:flex-row items-center gap-4 bg-stone-50 p-2 rounded-sm w-full sm:w-auto border border-stone-100 shadow-inner">
             <div className="grid grid-cols-4 bg-white shadow-sm overflow-hidden rounded-sm w-full sm:w-auto ring-1 ring-stone-100">
                {(Object.entries(LANGUAGES) as [Language, string][]).map(([full, short]) => (
                  <button key={full} type="button" onClick={() => handleSourceLangChange(full)}
                    className={`px-3 sm:px-5 py-2.5 text-[9px] font-black tracking-widest border-r border-stone-100 last:border-r-0 transition-all ${sourceLang === full ? 'bg-stone-900 text-white' : 'text-stone-300 hover:text-stone-600'}`}>
                    {short}
                  </button>
                ))}
             </div>
             <button type="button" onClick={swapLanguages} className="text-stone-300 hover:text-[#7c1a1a] transition-all p-2 hover:rotate-180 duration-500 transform sm:rotate-0 rotate-90 active:scale-90">
               <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="m17 2 4 4-4 4"/><path d="M3 11v-1a4 4 0 0 1 4-4h14"/><path d="m7 22-4-4 4-4"/><path d="M21 13v1a4 4 0 0 1-4 4H3"/></svg>
             </button>
             <div className="grid grid-cols-4 bg-white shadow-sm overflow-hidden rounded-sm w-full sm:w-auto ring-1 ring-stone-100">
                {(Object.entries(LANGUAGES) as [Language, string][]).map(([full, short]) => (
                  <button key={full} type="button" onClick={() => handleTargetLangChange(full)}
                    className={`px-3 sm:px-5 py-2.5 text-[9px] font-black tracking-widest border-r border-stone-100 last:border-r-0 transition-all ${targetLang === full ? 'bg-[#7c1a1a] text-white' : 'text-stone-300 hover:text-stone-600'}`}>
                    {short}
                  </button>
                ))}
             </div>
          </div>
          <div className="flex items-center gap-4 bg-stone-50/50 px-4 py-2 rounded-full border border-stone-100">
            <span className="text-[10px] uppercase tracking-[0.2em] text-stone-400 font-black">AUTO-PRONOUNCE</span>
            <button onClick={async () => { try { await resumeAudioContext(); } catch(e){} setAutoAudio(!autoAudio); triggerHaptic('light'); }} className={`w-10 h-5 rounded-full relative transition-all duration-300 p-1 ${autoAudio ? 'bg-[#7c1a1a]' : 'bg-stone-200'}`}>
              <div className={`w-3 h-3 bg-white rounded-full transition-all shadow-md ${autoAudio ? 'translate-x-5' : 'translate-x-0'}`} />
            </button>
          </div>
        </div>
      </div>

      <div className="relative w-full" ref={suggestionRef}>
        <form onSubmit={(e) => { e.preventDefault(); handleSearch(); }} className="relative z-20">
          <div className={`bg-white border border-stone-200 shadow-sm hover:border-[#7c1a1a]/50 focus-within:border-[#7c1a1a] focus-within:ring-8 focus-within:ring-[#7c1a1a]/5 transition-all group rounded-sm overflow-hidden flex items-stretch min-h-[70px] md:min-h-[120px] ${isListening ? 'ring-4 ring-[#7c1a1a]/20 animate-pulse' : ''}`}>
            <div className="flex-1 flex items-center px-6 md:px-12 relative">
              <input 
                ref={inputRef}
                type="text" 
                value={query} 
                onChange={(e) => setQuery(e.target.value)} 
                onFocus={async () => { try { await resumeAudioContext(); } catch(e){} if (suggestions.length > 0) setShowSuggestions(true); }}
                onKeyDown={handleKeyDown}
                placeholder={isListening ? "Listening..." : "Summon an inscription..."}
                className="w-full text-2xl md:text-6xl serif bg-transparent outline-none text-stone-900 placeholder:text-stone-100 lowercase font-medium tracking-tighter leading-none" 
              />
              <button 
                type="button" 
                onClick={startVoiceSearch}
                className={`ml-4 p-3 rounded-full transition-all ${isListening ? 'bg-[#7c1a1a] text-white scale-110 shadow-lg' : 'text-stone-500 hover:text-[#7c1a1a] hover:bg-stone-50'}`}
              >
                <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3.5" strokeLinecap="round" strokeLinejoin="round"><path d="M12 2a3 3 0 0 0-3 3v7a3 3 0 0 0 6 0V5a3 3 0 0 0-3-3Z"/><path d="M19 10v2a7 7 0 0 1-14 0v-2"/><line x1="12" x2="12" y1="19" y2="22"/></svg>
              </button>
            </div>
            <button type="submit" disabled={loading} className="bg-stone-50 border-l border-stone-100 px-6 md:px-14 text-stone-600 hover:text-[#7c1a1a] hover:bg-white transition-all transform active:scale-95 flex items-center justify-center">
              {loading ? <div className="w-6 h-6 md:w-12 md:h-12 border-[4px] border-[#7c1a1a] border-t-transparent rounded-full animate-spin" /> : <svg xmlns="http://www.w3.org/2000/svg" className="w-6 h-6 md:w-16 md:h-16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M5 12h14"/><path d="m12 5 7 7-7 7"/></svg>}
            </button>
          </div>
        </form>

        {searchError && (
          <p className="mt-4 text-red-600 text-[10px] uppercase tracking-widest font-black animate-in fade-in slide-in-from-top-1">
            {searchError}
          </p>
        )}

        {showSuggestions && (
          <div className="absolute top-full left-0 right-0 bg-white border border-stone-200 shadow-2xl z-10 animate-in fade-in slide-in-from-top-2 duration-500 rounded-b-sm overflow-hidden max-h-[400px] overflow-y-auto">
             {suggestions.map((s, idx) => (
               <button 
                 key={idx} 
                 onClick={() => { setQuery(s.term); handleSearch(s.term); }}
                 onMouseEnter={() => setSelectedIndex(idx)}
                 className={`w-full text-left px-8 md:px-12 py-5 hover:bg-stone-50 border-b border-stone-50 last:border-0 flex items-center justify-between group transition-all ${selectedIndex === idx ? 'bg-stone-50 border-l-[4px] border-l-[#7c1a1a]' : 'border-l-[4px] border-l-transparent'}`}
               >
                 <span className={`serif text-xl md:text-2xl transition-colors ${selectedIndex === idx ? 'text-stone-900' : 'text-stone-600'}`}>{s.term}</span>
                 <span className={`text-[8px] md:text-[9px] uppercase tracking-[0.3em] font-black px-3 py-1.5 rounded-sm border ${
                   s.source === 'local' ? 'bg-[#7c1a1a]/5 text-[#7c1a1a] border-[#7c1a1a]/10' : 
                   s.source === 'seed' ? 'bg-stone-100 text-stone-500 border-stone-200' : 
                   'bg-stone-900 text-white border-stone-900 shadow-sm'
                 }`}>
                   {s.source === 'local' ? 'Archive' : s.source === 'seed' ? 'Scribe' : 'Global'}
                 </span>
               </button>
             ))}
          </div>
        )}
      </div>

      <div className={`min-h-[60px] transition-opacity duration-300 ${loading ? 'opacity-40 pointer-events-none' : 'opacity-100'}`}>
        {result ? (
          <ResultCard entry={result} onSearchTerm={(term) => handleSearch(term)} />
        ) : !loading && (
          <div className="py-20 text-center space-y-12">
            <div className="max-w-2xl mx-auto px-4">
              <h2 className="serif text-4xl md:text-6xl font-black text-stone-900 mb-6 lowercase tracking-tighter">Scholarly Discovery</h2>
              <p className="text-stone-400 serif italic text-xl md:text-2xl leading-relaxed">
                The engine awaits your command. Search for etymologies, or test your mastery in the <button onClick={onStartArena} className="text-[#7c1a1a] underline underline-offset-8 decoration-1 hover:decoration-2 transition-all">Scholarly Arena</button>.
              </p>
            </div>
          </div>
        )}
      </div>

      <div className="pt-16 md:pt-32 border-t border-stone-100">
        <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-8 mb-12">
          <div className="border-l-[3px] border-[#7c1a1a] pl-6 md:pl-10 py-1">
            <h2 className="text-[12px] uppercase tracking-[0.5em] text-stone-900 font-black mb-1">Archival Chronicles</h2>
            <p className="text-stone-400 text-[9px] uppercase tracking-[0.2em] font-medium italic">Persistent insights</p>
          </div>
          <button 
            onClick={onStartArena} 
            className="group relative bg-[#7c1a1a] text-white px-10 py-4 flex items-center gap-4 shadow-xl hover:shadow-[#7c1a1a]/30 hover:-translate-y-1 active:translate-y-0 transition-all rounded-sm w-full sm:w-auto justify-center"
          >
            <svg className="group-hover:rotate-45 transition-transform duration-500" xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="currentColor"><path d="M12 2l3.09 6.26L22 9.27l-5 4.87 1.18 6.88L12 17.77l-6.18 3.25L7 14.14 2 9.27l6.91-1.01L12 2z"/></svg>
            <span className="text-[10px] uppercase tracking-[0.5em] font-black relative z-10">Start Arena</span>
          </button>
        </div>
        <HistoryGrid history={history} onEntryClick={onEntryClick} />
      </div>
    </div>
  );
};

export default Dictionary;
